using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Models;
using System;

namespace ContosoUniversity.Tests.Models;

[TestClass]
public sealed class PersonTests
{
    [TestMethod]
    public void FullName_ReturnsLastNameCommaFirstName()
    {
        // Arrange - use Student as concrete subclass of Person
        var student = new Student
        {
            LastName = "Smith",
            FirstMidName = "John",
            EnrollmentDate = DateTime.Today
        };

        // Act
        var result = student.FullName;

        // Assert
        Assert.AreEqual("Smith, John", result);
    }

    [TestMethod]
    [DataRow("Doe", "Jane", "Doe, Jane", DisplayName = "Standard names")]
    [DataRow("O'Brien", "Mary", "O'Brien, Mary", DisplayName = "Name with apostrophe")]
    [DataRow("Li", "X", "Li, X", DisplayName = "Short names")]
    public void FullName_VariousNames_ReturnsCorrectFormat(string lastName, string firstName, string expected)
    {
        // Arrange
        var instructor = new Instructor
        {
            LastName = lastName,
            FirstMidName = firstName,
            HireDate = DateTime.Today
        };

        // Act
        var result = instructor.FullName;

        // Assert
        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void ID_DefaultsToZero()
    {
        var student = new Student();
        Assert.AreEqual(0, student.ID);
    }

    [TestMethod]
    public void ID_CanBeSetAndRetrieved()
    {
        var student = new Student { ID = 42 };
        Assert.AreEqual(42, student.ID);
    }

    [TestMethod]
    public void LastName_CanBeSetAndRetrieved()
    {
        var student = new Student { LastName = "TestName" };
        Assert.AreEqual("TestName", student.LastName);
    }

    [TestMethod]
    public void FirstMidName_CanBeSetAndRetrieved()
    {
        var student = new Student { FirstMidName = "TestFirst" };
        Assert.AreEqual("TestFirst", student.FirstMidName);
    }
}

