using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Models;
using System;

namespace ContosoUniversity.Tests.Models;

[TestClass]
public sealed class NotificationModelTests
{
    [TestMethod]
    public void Notification_PropertiesCanBeSetAndRetrieved()
    {
        var now = DateTime.Now;
        var notification = new Notification
        {
            Id = 1,
            EntityType = "Student",
            EntityId = "42",
            Operation = "CREATE",
            Message = "New Student created",
            CreatedAt = now,
            CreatedBy = "Admin",
            IsRead = false,
            ReadAt = null
        };

        Assert.AreEqual(1, notification.Id);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("42", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("New Student created", notification.Message);
        Assert.AreEqual(now, notification.CreatedAt);
        Assert.AreEqual("Admin", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
        Assert.IsNull(notification.ReadAt);
    }

    [TestMethod]
    public void Notification_IsRead_CanBeSetToTrue()
    {
        var readTime = DateTime.Now;
        var notification = new Notification
        {
            IsRead = true,
            ReadAt = readTime
        };

        Assert.IsTrue(notification.IsRead);
        Assert.AreEqual(readTime, notification.ReadAt);
    }

    [TestMethod]
    public void EntityOperation_HasExpectedValues()
    {
        Assert.AreEqual(0, (int)EntityOperation.CREATE);
        Assert.AreEqual(1, (int)EntityOperation.UPDATE);
        Assert.AreEqual(2, (int)EntityOperation.DELETE);
    }

    [TestMethod]
    [DataRow(EntityOperation.CREATE, "CREATE", DisplayName = "CREATE enum to string")]
    [DataRow(EntityOperation.UPDATE, "UPDATE", DisplayName = "UPDATE enum to string")]
    [DataRow(EntityOperation.DELETE, "DELETE", DisplayName = "DELETE enum to string")]
    public void EntityOperation_ToString_ReturnsExpectedName(EntityOperation op, string expected)
    {
        Assert.AreEqual(expected, op.ToString());
    }

    [TestMethod]
    public void Notification_DefaultValues()
    {
        var notification = new Notification();

        Assert.AreEqual(0, notification.Id);
        Assert.IsNull(notification.EntityType);
        Assert.IsNull(notification.EntityId);
        Assert.IsNull(notification.Operation);
        Assert.IsNull(notification.Message);
        Assert.IsFalse(notification.IsRead);
        Assert.IsNull(notification.ReadAt);
        Assert.IsNull(notification.CreatedBy);
    }
}

