    public void Department_PropertiesCanBeSetAndRetrieved()
    {
        var startDate = new DateTime(2007, 9, 1);
        var department = new Department
        {
            DepartmentID = 1,
            Name = "Engineering",
            Budget = 350000m,
            StartDate = startDate,
            InstructorID = 5
        };

        Assert.AreEqual(1, department.DepartmentID);
        Assert.AreEqual("Engineering", department.Name);
        Assert.AreEqual(350000m, department.Budget);
        Assert.AreEqual(startDate, department.StartDate);
        Assert.AreEqual(5, department.InstructorID);
    }

    [TestMethod]
    public void Department_InstructorID_IsNullable()
    {
        var department = new Department { InstructorID = null };
        Assert.IsNull(department.InstructorID);
    }

    [TestMethod]
    public void Department_RowVersion_CanBeSet()
    {
        var rowVersion = new byte[] { 0x01, 0x02, 0x03 };
        var department = new Department { RowVersion = rowVersion };

        CollectionAssert.AreEqual(rowVersion, department.RowVersion);
    }

    [TestMethod]
    public void Department_AdministratorNavigation_CanBeSet()
    {
        var admin = new Instructor
        {
            ID = 5,
            LastName = "Smith",
            FirstMidName = "John",
            HireDate = DateTime.Today
        };
        var department = new Department { Administrator = admin };

        Assert.AreEqual("Smith", department.Administrator.LastName);
        Assert.AreEqual("John", department.Administrator.FirstMidName);
    }

    [TestMethod]
    public void Department_CoursesCollection_CanBeSet()
    {
        var courses = new List<Course>
        {
            new Course { CourseID = 1, Title = "Calculus" },
            new Course { CourseID = 2, Title = "Algebra" }
        };
        var department = new Department { Courses = courses };

        Assert.AreEqual(2, department.Courses.Count);
    }

    [TestMethod]
    public void Department_DefaultValues()
    {
        var department = new Department();

        Assert.AreEqual(0, department.DepartmentID);
        Assert.IsNull(department.Name);
        Assert.AreEqual(0m, department.Budget);
        Assert.IsNull(department.InstructorID);
        Assert.IsNull(department.RowVersion);
        Assert.IsNull(department.Administrator);
        Assert.IsNull(department.Courses);
    }
}

