using Microsoft.VisualStudio.TestTools.UnitTesting;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PaginatedListTests
{
    [TestMethod]
    public void Constructor_SetsPageIndex()
    {
        var items = new List<string> { "a", "b" };
        var list = new PaginatedList<string>(items, 10, 2, 5);

        Assert.AreEqual(2, list.PageIndex);
    }

    [TestMethod]
    public void Constructor_CalculatesTotalPages()
    {
        var items = new List<string> { "a" };
        var list = new PaginatedList<string>(items, 10, 1, 3);

        // ceil(10 / 3) = 4
        Assert.AreEqual(4, list.TotalPages);
    }

    [TestMethod]
    public void Constructor_AddsItemsToList()
    {
        var items = new List<int> { 1, 2, 3 };
        var list = new PaginatedList<int>(items, 3, 1, 10);

        Assert.AreEqual(3, list.Count);
        Assert.AreEqual(1, list[0]);
        Assert.AreEqual(2, list[1]);
        Assert.AreEqual(3, list[2]);
    }

    [TestMethod]
    [DataRow(10, 3, 4, DisplayName = "10 items, pageSize 3 = 4 pages")]
    [DataRow(10, 5, 2, DisplayName = "10 items, pageSize 5 = 2 pages")]
    [DataRow(10, 10, 1, DisplayName = "10 items, pageSize 10 = 1 page")]
    [DataRow(1, 10, 1, DisplayName = "1 item, pageSize 10 = 1 page")]
    [DataRow(11, 5, 3, DisplayName = "11 items, pageSize 5 = 3 pages")]
    public void TotalPages_CalculatesCorrectly(int totalCount, int pageSize, int expectedPages)
    {
        var list = new PaginatedList<int>(new List<int>(), totalCount, 1, pageSize);
        Assert.AreEqual(expectedPages, list.TotalPages);
    }

    [TestMethod]
    public void HasPreviousPage_ReturnsFalse_WhenOnFirstPage()
    {
        var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
        Assert.IsFalse(list.HasPreviousPage);
    }

    [TestMethod]
    public void HasPreviousPage_ReturnsTrue_WhenOnSecondPage()
    {
        var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);
        Assert.IsTrue(list.HasPreviousPage);
    }

    [TestMethod]
    public void HasNextPage_ReturnsTrue_WhenNotOnLastPage()
    {
        var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
        Assert.IsTrue(list.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_ReturnsFalse_WhenOnLastPage()
    {
        var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);
        Assert.IsFalse(list.HasNextPage);
    }

    [TestMethod]
    public void Create_ReturnsCorrectPage()
    {
        var source = Enumerable.Range(1, 20).AsQueryable();

        var result = PaginatedList<int>.Create(source, 2, 5);

        Assert.AreEqual(2, result.PageIndex);
        Assert.AreEqual(4, result.TotalPages);
