using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Services;
using ContosoUniversity.Models;
using System;

namespace ContosoUniversity.Tests.Services;

[TestClass]
public sealed class NotificationServiceTests
{
    private NotificationService _service;

    [TestInitialize]
    public void Setup()
    {
        _service = new NotificationService();
        // Drain any leftover notifications from the static queue
        while (_service.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void Cleanup()
    {
        // Drain queue so tests don't interfere with each other
        while (_service.ReceiveNotification() != null) { }
        _service.Dispose();
    }

    [TestMethod]
    public void SendNotification_WithDisplayName_CreatesCorrectMessage()
    {
        // Act
        _service.SendNotification("Student", "42", "John Smith", EntityOperation.CREATE, "Admin");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("42", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("New Student 'John Smith' has been created", notification.Message);
        Assert.AreEqual("Admin", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_UsesIdInMessage()
    {
        // Act
        _service.SendNotification("Course", "100", EntityOperation.UPDATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Course (ID: 100) has been updated", notification.Message);
    }

    [TestMethod]
    public void SendNotification_Delete_CreatesDeleteMessage()
    {
        // Act
        _service.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE, "System");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Department 'Engineering' has been deleted", notification.Message);
        Assert.AreEqual("DELETE", notification.Operation);
    }

    [TestMethod]
    public void SendNotification_WithoutUserName_DefaultsToSystem()
    {
        // Act
        _service.SendNotification("Student", "1", EntityOperation.CREATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_SetsCreatedAt()
    {
        // Arrange
        var before = DateTime.Now;

        // Act
        _service.SendNotification("Student", "1", EntityOperation.CREATE);

        // Assert
        var after = DateTime.Now;
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after);
    }

    [TestMethod]
    public void ReceiveNotification_ReturnsNull_WhenQueueIsEmpty()
    {
        var result = _service.ReceiveNotification();
        Assert.IsNull(result);
    }

    [TestMethod]
    public void ReceiveNotification_ReturnsFifo()
    {
        // Arrange
        _service.SendNotification("A", "1", EntityOperation.CREATE);
        _service.SendNotification("B", "2", EntityOperation.UPDATE);
        _service.SendNotification("C", "3", EntityOperation.DELETE);

        // Act & Assert - FIFO order
        var first = _service.ReceiveNotification();
        Assert.AreEqual("A", first.EntityType);

        var second = _service.ReceiveNotification();
        Assert.AreEqual("B", second.EntityType);

        var third = _service.ReceiveNotification();
        Assert.AreEqual("C", third.EntityType);

        // Queue should now be empty
        Assert.IsNull(_service.ReceiveNotification());
    }

    [TestMethod]
    public void SendNotification_MultipleOverload_WithoutDisplayName()
    {
        // Act
        _service.SendNotification("Instructor", "7", null, EntityOperation.UPDATE, "Admin");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Instructor (ID: 7) has been updated", notification.Message);
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        // MarkAsRead is a no-op for in-memory implementation, just verify no exception
        _service.MarkAsRead(42);
    }

    [TestMethod]
    public void Dispose_DoesNotThrow()
    {
        var service = new NotificationService();
        service.Dispose();
        // No exception means success
    }

    [TestMethod]
    [DataRow(EntityOperation.CREATE, "Student", "1", "Jane Doe", "New Student 'Jane Doe' has been created", DisplayName = "CREATE with display name")]
    [DataRow(EntityOperation.UPDATE, "Course", "100", "Chemistry", "Course 'Chemistry' has been updated", DisplayName = "UPDATE with display name")]
    [DataRow(EntityOperation.DELETE, "Department", "5", "Math", "Department 'Math' has been deleted", DisplayName = "DELETE with display name")]
    public void SendNotification_GeneratesCorrectMessage(EntityOperation operation, string entityType, string entityId, string displayName, string expectedMessage)
    {
        // Act
        _service.SendNotification(entityType, entityId, displayName, operation);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual(expectedMessage, notification.Message);
    }
}

