using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.EntityFrameworkCore;
using System;
using System.Linq;

namespace ContosoUniversity.Tests.Data;

[TestClass]
public sealed class SchoolContextTests
{
    [TestMethod]
    public void SchoolContext_CanBeCreated()
    {
        using var context = TestHelpers.CreateInMemoryContext();
        Assert.IsNotNull(context);
    }

    [TestMethod]
    public void SchoolContext_CanAddAndRetrieveStudent()
    {
        using var context = TestHelpers.CreateInMemoryContext();
        var student = new Student
        {
            LastName = "Test",
            FirstMidName = "User",
            EnrollmentDate = new DateTime(2023, 1, 1)
        };

        context.Students.Add(student);
        context.SaveChanges();

        var retrieved = context.Students.First();
        Assert.AreEqual("Test", retrieved.LastName);
        Assert.AreEqual("User", retrieved.FirstMidName);
    }

    [TestMethod]
    public void SchoolContext_CanAddAndRetrieveInstructor()
    {
        using var context = TestHelpers.CreateInMemoryContext();
        var instructor = new Instructor
        {
            LastName = "Prof",
            FirstMidName = "Test",
            HireDate = new DateTime(2020, 1, 1)
        };

        context.Instructors.Add(instructor);
        context.SaveChanges();

        var retrieved = context.Instructors.First();
        Assert.AreEqual("Prof", retrieved.LastName);
        Assert.AreEqual(new DateTime(2020, 1, 1), retrieved.HireDate);
    }

    [TestMethod]
    public void SchoolContext_CanAddAndRetrieveCourse()
    {
        using var context = TestHelpers.CreateInMemoryContext();

        // Add a department first (required FK)
        var dept = new Department
        {
            Name = "Test Dept",
            Budget = 100000m,
            StartDate = new DateTime(2020, 1, 1)
        };
        context.Departments.Add(dept);
        context.SaveChanges();

        var course = new Course
        {
            CourseID = 1001,
            Title = "Test Course",
            Credits = 3,
            DepartmentID = dept.DepartmentID
        };
        context.Courses.Add(course);
        context.SaveChanges();

        var retrieved = context.Courses.First();
        Assert.AreEqual(1001, retrieved.CourseID);
        Assert.AreEqual("Test Course", retrieved.Title);
        Assert.AreEqual(3, retrieved.Credits);
    }

    [TestMethod]
    public void SchoolContext_CanAddAndRetrieveDepartment()
    {
        using var context = TestHelpers.CreateInMemoryContext();
        var dept = new Department
        {
            Name = "Engineering",
            Budget = 350000m,
            StartDate = new DateTime(2007, 9, 1)
        };

        context.Departments.Add(dept);
        context.SaveChanges();

        var retrieved = context.Departments.First();
        Assert.AreEqual("Engineering", retrieved.Name);
        Assert.AreEqual(350000m, retrieved.Budget);
    }

    [TestMethod]
    public void SchoolContext_CanAddAndRetrieveEnrollment()
    {
        using var context = TestHelpers.CreateInMemoryContext();

        var student = new Student { LastName = "S", FirstMidName = "T", EnrollmentDate = DateTime.Today };
        context.Students.Add(student);

        var dept = new Department { Name = "D", Budget = 1000m, StartDate = DateTime.Today };
        context.Departments.Add(dept);
        context.SaveChanges();

        var course = new Course { CourseID = 999, Title = "C", Credits = 1, DepartmentID = dept.DepartmentID };
        context.Courses.Add(course);
        context.SaveChanges();

        var enrollment = new Enrollment
        {
            CourseID = course.CourseID,
            StudentID = student.ID,
            Grade = Grade.A
        };
        context.Enrollments.Add(enrollment);
        context.SaveChanges();

        var retrieved = context.Enrollments.First();
        Assert.AreEqual(Grade.A, retrieved.Grade);
        Assert.AreEqual(course.CourseID, retrieved.CourseID);
        Assert.AreEqual(student.ID, retrieved.StudentID);
    }

    [TestMethod]
    public void SchoolContext_CourseAssignment_CompositeKey()
    {
        using var context = TestHelpers.CreateInMemoryContext();

        var instructor = new Instructor { LastName = "I", FirstMidName = "T", HireDate = DateTime.Today };
        context.Instructors.Add(instructor);

        var dept = new Department { Name = "D", Budget = 1000m, StartDate = DateTime.Today };
        context.Departments.Add(dept);
        context.SaveChanges();

        var course = new Course { CourseID = 500, Title = "C", Credits = 1, DepartmentID = dept.DepartmentID };
        context.Courses.Add(course);
        context.SaveChanges();

        var assignment = new CourseAssignment
        {
            CourseID = course.CourseID,
            InstructorID = instructor.ID
        };
        context.CourseAssignments.Add(assignment);
        context.SaveChanges();

        var retrieved = context.CourseAssignments.First();
        Assert.AreEqual(course.CourseID, retrieved.CourseID);
        Assert.AreEqual(instructor.ID, retrieved.InstructorID);
    }

    [TestMethod]
    public void SchoolContext_HasAllDbSets()
    {
        using var context = TestHelpers.CreateInMemoryContext();

        Assert.IsNotNull(context.Courses);
        Assert.IsNotNull(context.Enrollments);
        Assert.IsNotNull(context.Departments);
        Assert.IsNotNull(context.OfficeAssignments);
        Assert.IsNotNull(context.CourseAssignments);
        Assert.IsNotNull(context.People);
        Assert.IsNotNull(context.Students);
        Assert.IsNotNull(context.Instructors);
        Assert.IsNotNull(context.Notifications);
    }
}

