        _context.Students.Add(new Student { LastName = "C", FirstMidName = "C", EnrollmentDate = date2 });
        _context.SaveChanges();

        // Act
        var result = _controller.About();

        // Assert
        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as System.Collections.Generic.List<ContosoUniversity.Models.SchoolViewModels.EnrollmentDateGroup>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count);
    }

    [TestMethod]
    public void About_WithNoStudents_ReturnsEmptyList()
    {
        var result = _controller.About();

        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as System.Collections.Generic.List<ContosoUniversity.Models.SchoolViewModels.EnrollmentDateGroup>;
        Assert.IsNotNull(model);
        Assert.AreEqual(0, model.Count);
    }

    [TestMethod]
    public void About_GroupsStudentsByEnrollmentDate()
    {
        // Arrange
        var date = new DateTime(2023, 9, 1);
        _context.Students.Add(new Student { LastName = "A", FirstMidName = "A", EnrollmentDate = date });
        _context.Students.Add(new Student { LastName = "B", FirstMidName = "B", EnrollmentDate = date });
        _context.Students.Add(new Student { LastName = "C", FirstMidName = "C", EnrollmentDate = date });
        _context.SaveChanges();

        // Act
        var result = _controller.About();

        // Assert
        var viewResult = result as ViewResult;
        var model = viewResult.Model as System.Collections.Generic.List<ContosoUniversity.Models.SchoolViewModels.EnrollmentDateGroup>;
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual(3, model[0].StudentCount);
        Assert.AreEqual(date, model[0].EnrollmentDate);
    }
}

