using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Hosting;
using Microsoft.Extensions.Logging;
using Moq;
using System;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class CoursesControllerTests
{
    private SchoolContext _context;
    private CoursesController _controller;
    private Mock<IWebHostEnvironment> _mockEnv;
    private Mock<ILogger<CoursesController>> _mockLogger;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _mockEnv = new Mock<IWebHostEnvironment>();
        _mockEnv.Setup(e => e.WebRootPath).Returns("/wwwroot");
        _mockEnv.Setup(e => e.ContentRootPath).Returns("/content");
        _mockLogger = new Mock<ILogger<CoursesController>>();
        _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);

        _controller.ControllerContext = new ControllerContext
        {
            HttpContext = new DefaultHttpContext()
        };
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    private void SeedCourses()
    {
        var dept = new Department
        {
            Name = "Engineering",
            Budget = 350000m,
            StartDate = new DateTime(2007, 9, 1)
        };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        _context.Courses.AddRange(
            new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = dept.DepartmentID },
            new Course { CourseID = 1045, Title = "Calculus", Credits = 4, DepartmentID = dept.DepartmentID },
            new Course { CourseID = 2021, Title = "Composition", Credits = 3, DepartmentID = dept.DepartmentID }
        );
        _context.SaveChanges();
    }

    // --- Index Tests ---

    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        SeedCourses();

        var result = _controller.Index();

        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void Index_ReturnsAllCourses()
    {
        SeedCourses();

        var result = _controller.Index() as ViewResult;
        var model = result.Model as System.Collections.Generic.List<Course>;

        Assert.AreEqual(3, model.Count);
    }

    // --- Details Tests ---

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);

        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual(400, statusResult.StatusCode);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithCourse()
    {
        SeedCourses();

        var result = _controller.Details(1050) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Course;
        Assert.IsNotNull(model);
        Assert.AreEqual("Chemistry", model.Title);
        Assert.AreEqual(1050, model.CourseID);
    }

    // --- Create GET Tests ---

    [TestMethod]
    public void Create_Get_ReturnsViewWithCourse()
    {
        SeedCourses();

        var result = _controller.Create() as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Course;
        Assert.IsNotNull(model);
    }

    // --- Create POST Tests ---

    [TestMethod]
    public void Create_ValidCourse_RedirectsToIndex()
    {
        SeedCourses();
        var dept = _context.Departments.First();
        var course = new Course
        {
            CourseID = 9999,
            Title = "New Course",
            Credits = 3,
            DepartmentID = dept.DepartmentID
        };

        var result = _controller.Create(course, null);

        Assert.IsInstanceOfType<RedirectToActionResult>(result);
        var redirect = result as RedirectToActionResult;
        Assert.AreEqual("Index", redirect.ActionName);
    }

    [TestMethod]
    public void Create_ValidCourse_SavesToDB()
    {
        SeedCourses();
        var dept = _context.Departments.First();
        var course = new Course
        {
            CourseID = 8888,
            Title = "Saved Course",
            Credits = 2,
            DepartmentID = dept.DepartmentID
        };

        _controller.Create(course, null);

        var saved = _context.Courses.Find(8888);
        Assert.IsNotNull(saved);
        Assert.AreEqual("Saved Course", saved.Title);
        Assert.AreEqual(2, saved.Credits);
    }

    [TestMethod]
    public void Create_InvalidModel_ReturnsView()
    {
        SeedCourses();
        _controller.ModelState.AddModelError("Title", "Required");

        var course = new Course { CourseID = 7777 };

        var result = _controller.Create(course, null);

        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void Create_WithInvalidImageExtension_ReturnsViewWithError()
    {
        SeedCourses();
        var dept = _context.Departments.First();
        var course = new Course
        {
            CourseID = 6666,
            Title = "Test",
            Credits = 3,
            DepartmentID = dept.DepartmentID
        };

        var mockFile = new Mock<IFormFile>();
        mockFile.Setup(f => f.FileName).Returns("test.exe");
        mockFile.Setup(f => f.Length).Returns(100);

        var result = _controller.Create(course, mockFile.Object);

        Assert.IsInstanceOfType<ViewResult>(result);
        Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [TestMethod]
    public void Create_WithOversizedImage_ReturnsViewWithError()
    {
        SeedCourses();
        var dept = _context.Departments.First();
        var course = new Course
        {
            CourseID = 5555,
            Title = "Test",
            Credits = 3,
            DepartmentID = dept.DepartmentID
        };

        var mockFile = new Mock<IFormFile>();
        mockFile.Setup(f => f.FileName).Returns("large.jpg");
        mockFile.Setup(f => f.Length).Returns(10 * 1024 * 1024); // 10MB

        var result = _controller.Create(course, mockFile.Object);

        Assert.IsInstanceOfType<ViewResult>(result);
        Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    // --- Edit GET Tests ---

    [TestMethod]
    public void Edit_NullId_ReturnsBadRequest()
    {
        var result = _controller.Edit(null as int?);

        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual(400, statusResult.StatusCode);
    }

    [TestMethod]
    public void Edit_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Edit(999);

        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void Edit_ValidId_ReturnsViewWithCourse()
    {
        SeedCourses();

        var result = _controller.Edit(1050) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Course;
        Assert.AreEqual("Chemistry", model.Title);
    }

    // --- Edit POST Tests ---

    [TestMethod]
    public void Edit_ValidCourse_RedirectsToIndex()
    {
        SeedCourses();
        var existing = _context.Courses.Find(1050);
        _context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var updatedCourse = new Course
        {
            CourseID = 1050,
            Title = "Updated Chemistry",
            Credits = 4,
            DepartmentID = existing.DepartmentID
        };

        var result = _controller.Edit(updatedCourse, null);

        Assert.IsInstanceOfType<RedirectToActionResult>(result);
    }

    [TestMethod]
    public void Edit_InvalidModel_ReturnsView()
    {
        SeedCourses();
        _controller.ModelState.AddModelError("Title", "Required");

        var course = new Course { CourseID = 1050 };

        var result = _controller.Edit(course, null);

        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void Edit_WithInvalidImageExtension_ReturnsViewWithError()
    {
        SeedCourses();
        var existing = _context.Courses.Find(1050);
        _context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var course = new Course
        {
            CourseID = 1050,
            Title = "Chemistry",
            Credits = 3,
            DepartmentID = existing.DepartmentID
        };

        var mockFile = new Mock<IFormFile>();
        mockFile.Setup(f => f.FileName).Returns("test.pdf");
        mockFile.Setup(f => f.Length).Returns(100);

        var result = _controller.Edit(course, mockFile.Object);

        Assert.IsInstanceOfType<ViewResult>(result);
        Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    // --- Delete GET Tests ---

    [TestMethod]
    public void Delete_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null);

        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual(400, statusResult.StatusCode);
    }

    [TestMethod]
    public void Delete_ValidId_ReturnsViewWithCourse()
    {
        SeedCourses();

        var result = _controller.Delete(1050) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Course;
        Assert.AreEqual("Chemistry", model.Title);
    }

    // --- DeleteConfirmed POST Tests ---

    [TestMethod]
    public void DeleteConfirmed_RemovesCourseAndRedirects()
    {
        SeedCourses();

        var result = _controller.DeleteConfirmed(1050);

        Assert.IsInstanceOfType<RedirectToActionResult>(result);
        Assert.IsNull(_context.Courses.Find(1050));
    }

    [TestMethod]
    public void DeleteConfirmed_ReducesCourseCount()
    {
        SeedCourses();
        var initialCount = _context.Courses.Count();

        _controller.DeleteConfirmed(1050);

        Assert.AreEqual(initialCount - 1, _context.Courses.Count());
    }
}

