using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Http;
using System;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class DepartmentsControllerTests
{
    private SchoolContext _context;
    private DepartmentsController _controller;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _controller = new DepartmentsController(_context);

        _controller.ControllerContext = new ControllerContext
        {
            HttpContext = new DefaultHttpContext()
        };
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    private void SeedDepartmentsAndInstructors()
    {
        var instructor1 = new Instructor { LastName = "Smith", FirstMidName = "John", HireDate = new DateTime(2000, 1, 1) };
        var instructor2 = new Instructor { LastName = "Doe", FirstMidName = "Jane", HireDate = new DateTime(2005, 6, 1) };
        _context.Instructors.AddRange(instructor1, instructor2);
        _context.SaveChanges();

        _context.Departments.AddRange(
            new Department { Name = "Engineering", Budget = 350000m, StartDate = new DateTime(2007, 9, 1), InstructorID = instructor1.ID },
            new Department { Name = "Mathematics", Budget = 100000m, StartDate = new DateTime(2007, 9, 1), InstructorID = instructor2.ID }
        );
        _context.SaveChanges();
    }

    // --- Index Tests ---

    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        SeedDepartmentsAndInstructors();

        var result = _controller.Index();

        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void Index_ReturnsAllDepartments()
    {
        SeedDepartmentsAndInstructors();

        var result = _controller.Index() as ViewResult;
        var model = result.Model as System.Collections.Generic.List<Department>;

        Assert.AreEqual(2, model.Count);
    }

    // --- Details Tests ---

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);

        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual(400, statusResult.StatusCode);
    }

    [TestMethod]
    public void Details_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Details(999);

        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithDepartment()
    {
        SeedDepartmentsAndInstructors();
        var dept = _context.Departments.First();

        var result = _controller.Details(dept.DepartmentID) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Department;
        Assert.IsNotNull(model);
        Assert.AreEqual(dept.Name, model.Name);
    }

    // --- Create GET Tests ---

    [TestMethod]
    public void Create_Get_ReturnsViewResult()
    {
        SeedDepartmentsAndInstructors();

        var result = _controller.Create();

        Assert.IsInstanceOfType<ViewResult>(result);
    }

    // --- Create POST Tests ---

    [TestMethod]
    public void Create_ValidDepartment_RedirectsToIndex()
    {
        SeedDepartmentsAndInstructors();
        var instructor = _context.Instructors.First();

        var dept = new Department
        {
            Name = "New Dept",
            Budget = 50000m,
            StartDate = new DateTime(2023, 1, 1),
            InstructorID = instructor.ID
        };

        var result = _controller.Create(dept);

        Assert.IsInstanceOfType<RedirectToActionResult>(result);
        var redirect = result as RedirectToActionResult;
        Assert.AreEqual("Index", redirect.ActionName);
    }

    [TestMethod]
    public void Create_ValidDepartment_SavesToDB()
    {
        SeedDepartmentsAndInstructors();
        var instructor = _context.Instructors.First();

        var dept = new Department
        {
            Name = "Saved Dept",
            Budget = 75000m,
            StartDate = new DateTime(2023, 6, 1),
            InstructorID = instructor.ID
        };

        _controller.Create(dept);

        var saved = _context.Departments.FirstOrDefault(d => d.Name == "Saved Dept");
        Assert.IsNotNull(saved);
        Assert.AreEqual(75000m, saved.Budget);
    }

    [TestMethod]
    public void Create_InvalidModel_ReturnsView()
    {
        SeedDepartmentsAndInstructors();
        _controller.ModelState.AddModelError("Name", "Required");

        var dept = new Department();

        var result = _controller.Create(dept);

        Assert.IsInstanceOfType<ViewResult>(result);
    }

    // --- Edit GET Tests ---

    [TestMethod]
    public void Edit_NullId_ReturnsBadRequest()
    {
        var result = _controller.Edit(null as int?);

        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual(400, statusResult.StatusCode);
    }

    [TestMethod]
    public void Edit_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Edit(999);

        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void Edit_ValidId_ReturnsViewWithDepartment()
    {
        SeedDepartmentsAndInstructors();
        var dept = _context.Departments.First();

        var result = _controller.Edit(dept.DepartmentID) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Department;
        Assert.AreEqual(dept.Name, model.Name);
    }

    // --- Edit POST Tests ---

    [TestMethod]
    public void Edit_ValidDepartment_RedirectsToIndex()
    {
        SeedDepartmentsAndInstructors();
        var dept = _context.Departments.First();
        var instructorId = dept.InstructorID;
        _context.Entry(dept).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var updatedDept = new Department
        {
            DepartmentID = dept.DepartmentID,
            Name = "Updated",
            Budget = 999999m,
            StartDate = new DateTime(2023, 1, 1),
            InstructorID = instructorId
        };

        var result = _controller.Edit(updatedDept);

        Assert.IsInstanceOfType<RedirectToActionResult>(result);
    }

    [TestMethod]
    public void Edit_InvalidModel_ReturnsView()
    {
        SeedDepartmentsAndInstructors();
        _controller.ModelState.AddModelError("Name", "Required");

        var dept = new Department { DepartmentID = 1 };

        var result = _controller.Edit(dept);

        Assert.IsInstanceOfType<ViewResult>(result);
    }

    // --- Delete GET Tests ---

    [TestMethod]
    public void Delete_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null);

        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual(400, statusResult.StatusCode);
    }

    [TestMethod]
    public void Delete_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Delete(999);

        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void Delete_ValidId_ReturnsViewWithDepartment()
    {
        SeedDepartmentsAndInstructors();
        var dept = _context.Departments.First();

        var result = _controller.Delete(dept.DepartmentID) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Department;
        Assert.AreEqual(dept.Name, model.Name);
    }

    // --- DeleteConfirmed POST Tests ---

    [TestMethod]
    public void DeleteConfirmed_RemovesDepartmentAndRedirects()
    {
        SeedDepartmentsAndInstructors();
        var dept = _context.Departments.First();
        var deptId = dept.DepartmentID;

        var result = _controller.DeleteConfirmed(deptId);

        Assert.IsInstanceOfType<RedirectToActionResult>(result);
        Assert.IsNull(_context.Departments.Find(deptId));
    }

    [TestMethod]
    public void DeleteConfirmed_ReducesDepartmentCount()
    {
        SeedDepartmentsAndInstructors();
        var initialCount = _context.Departments.Count();
        var dept = _context.Departments.First();

        _controller.DeleteConfirmed(dept.DepartmentID);

        Assert.AreEqual(initialCount - 1, _context.Departments.Count());
    }
}

