using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Http;
using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class InstructorsControllerTests
{
    private SchoolContext _context;
    private InstructorsController _controller;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _controller = new InstructorsController(_context);

        _controller.ControllerContext = new ControllerContext
        {
            HttpContext = new DefaultHttpContext()
        };
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    private void SeedInstructorsWithCourses()
    {
        var dept = new Department { Name = "Engineering", Budget = 350000m, StartDate = new DateTime(2007, 9, 1) };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        var instructor1 = new Instructor
        {
            LastName = "Smith",
            FirstMidName = "John",
            HireDate = new DateTime(2000, 1, 1),
            CourseAssignments = new List<CourseAssignment>(),
            OfficeAssignment = new OfficeAssignment { Location = "Room 101" }
        };
        var instructor2 = new Instructor
        {
            LastName = "Doe",
            FirstMidName = "Jane",
            HireDate = new DateTime(2005, 6, 1),
            CourseAssignments = new List<CourseAssignment>()
        };
        _context.Instructors.AddRange(instructor1, instructor2);
        _context.SaveChanges();

        var course1 = new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = dept.DepartmentID };
        var course2 = new Course { CourseID = 1045, Title = "Calculus", Credits = 4, DepartmentID = dept.DepartmentID };
        _context.Courses.AddRange(course1, course2);
        _context.SaveChanges();

        _context.CourseAssignments.Add(new CourseAssignment { CourseID = 1050, InstructorID = instructor1.ID });
        _context.CourseAssignments.Add(new CourseAssignment { CourseID = 1045, InstructorID = instructor2.ID });
        _context.SaveChanges();
    }

    // --- Index Tests ---

    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        SeedInstructorsWithCourses();

        var result = _controller.Index(null, null);

        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void Index_ReturnsInstructorIndexData()
    {
        SeedInstructorsWithCourses();

        var result = _controller.Index(null, null) as ViewResult;
        var model = result.Model as ContosoUniversity.Models.SchoolViewModels.InstructorIndexData;

        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Instructors.Count());
    }

    [TestMethod]
    public void Index_WithInstructorId_ShowsCourses()
    {
        SeedInstructorsWithCourses();
        var instructor = _context.Instructors.First();

        var result = _controller.Index(instructor.ID, null) as ViewResult;
        var model = result.Model as ContosoUniversity.Models.SchoolViewModels.InstructorIndexData;

        Assert.IsNotNull(model.Courses);
        Assert.IsTrue(model.Courses.Any());
    }

    // --- Details Tests ---

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);

        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual(400, statusResult.StatusCode);
    }

    [TestMethod]
    public void Details_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Details(999);

        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithInstructor()
    {
        SeedInstructorsWithCourses();
        var instructor = _context.Instructors.First();

        var result = _controller.Details(instructor.ID) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.IsNotNull(model);
        Assert.AreEqual(instructor.LastName, model.LastName);
    }

    // --- Create GET Tests ---

    [TestMethod]
    public void Create_Get_ReturnsViewWithInstructor()
    {
        SeedInstructorsWithCourses();

        var result = _controller.Create() as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.IsNotNull(model);
        Assert.IsNotNull(model.CourseAssignments);
        Assert.AreEqual(0, model.CourseAssignments.Count);
    }

    // --- Create POST Tests ---

    [TestMethod]
    public void Create_ValidInstructor_RedirectsToIndex()
    {
        SeedInstructorsWithCourses();
        var instructor = new Instructor
        {
            LastName = "New",
            FirstMidName = "Instructor",
            HireDate = new DateTime(2023, 9, 1)
        };

        var result = _controller.Create(instructor, null);

        Assert.IsInstanceOfType<RedirectToActionResult>(result);
        var redirect = result as RedirectToActionResult;
        Assert.AreEqual("Index", redirect.ActionName);
    }

    [TestMethod]
    public void Create_ValidInstructor_SavesToDB()
    {
        SeedInstructorsWithCourses();
        var instructor = new Instructor
        {
            LastName = "Saved",
            FirstMidName = "Prof",
            HireDate = new DateTime(2023, 1, 1)
        };

        _controller.Create(instructor, null);

        var saved = _context.Instructors.FirstOrDefault(i => i.LastName == "Saved");
        Assert.IsNotNull(saved);
        Assert.AreEqual("Prof", saved.FirstMidName);
    }

    [TestMethod]
    public void Create_WithSelectedCourses_CreatesCourseAssignments()
    {
        SeedInstructorsWithCourses();
        var instructor = new Instructor
        {
            LastName = "WithCourses",
            FirstMidName = "Test",
            HireDate = new DateTime(2023, 1, 1)
        };

        var result = _controller.Create(instructor, new[] { "1050", "1045" });

        Assert.IsInstanceOfType<RedirectToActionResult>(result);
        var saved = _context.Instructors.Include(i => i.CourseAssignments)
            .FirstOrDefault(i => i.LastName == "WithCourses");
        Assert.IsNotNull(saved);
        Assert.AreEqual(2, saved.CourseAssignments.Count);
    }

    [TestMethod]
    public void Create_InvalidModel_ReturnsView()
    {
        SeedInstructorsWithCourses();
        _controller.ModelState.AddModelError("LastName", "Required");

        var instructor = new Instructor
        {
            HireDate = DateTime.Today,
            CourseAssignments = new List<CourseAssignment>()
        };

        var result = _controller.Create(instructor, null);

        Assert.IsInstanceOfType<ViewResult>(result);
    }

    // --- Delete GET Tests ---

    [TestMethod]
    public void Delete_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null);

        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual(400, statusResult.StatusCode);
    }

    [TestMethod]
    public void Delete_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Delete(999);

        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void Delete_ValidId_ReturnsViewWithInstructor()
    {
        SeedInstructorsWithCourses();
        var instructor = _context.Instructors.First();

        var result = _controller.Delete(instructor.ID) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.AreEqual(instructor.LastName, model.LastName);
    }

    // --- DeleteConfirmed POST Tests ---

    [TestMethod]
    public void DeleteConfirmed_RemovesInstructorAndRedirects()
    {
        SeedInstructorsWithCourses();
        var instructor = _context.Instructors.First();
        var instructorId = instructor.ID;

        var result = _controller.DeleteConfirmed(instructorId);

        Assert.IsInstanceOfType<RedirectToActionResult>(result);
        Assert.IsNull(_context.Instructors.Find(instructorId));
    }

    [TestMethod]
