using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Http;
using System;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class NotificationsControllerTests
{
    private SchoolContext _context;
    private NotificationsController _controller;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _controller = new NotificationsController(_context);

        _controller.ControllerContext = new ControllerContext
        {
            HttpContext = new DefaultHttpContext()
        };

        // Drain any leftover notifications from the static queue
        var svc = new NotificationService();
        while (svc.ReceiveNotification() != null) { }
        svc.Dispose();
    }

    [TestCleanup]
    public void Cleanup()
    {
        // Drain queue to prevent inter-test interference
        var svc = new NotificationService();
        while (svc.ReceiveNotification() != null) { }
        svc.Dispose();

        _controller.Dispose();
        _context.Dispose();
    }

    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        var result = _controller.Index();

        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void GetNotifications_ReturnsJsonResult()
    {
        var result = _controller.GetNotifications();

        Assert.IsInstanceOfType<JsonResult>(result);
    }

    [TestMethod]
    public void GetNotifications_EmptyQueue_ReturnsSuccessWithZeroCount()
    {
        var result = _controller.GetNotifications();

        Assert.IsNotNull(result);
        Assert.IsNotNull(result.Value);

        // Verify the anonymous type has success=true
        var value = result.Value;
        var successProp = value.GetType().GetProperty("success");
        Assert.IsNotNull(successProp);
        Assert.AreEqual(true, successProp.GetValue(value));

        var countProp = value.GetType().GetProperty("count");
        Assert.AreEqual(0, countProp.GetValue(value));
    }

    [TestMethod]
    public void GetNotifications_WithNotifications_ReturnsNotifications()
    {
        // Arrange - add notifications through the service
        var svc = new NotificationService();
        svc.SendNotification("Student", "1", "John", EntityOperation.CREATE, "Admin");
        svc.SendNotification("Course", "100", "Chemistry", EntityOperation.UPDATE, "System");

        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result.Value);
        var value = result.Value;
        var countProp = value.GetType().GetProperty("count");
        Assert.AreEqual(2, countProp.GetValue(value));

        svc.Dispose();
    }

    [TestMethod]
    public void GetNotifications_LimitsToTenNotifications()
    {
        // Arrange - add more than 10 notifications
        var svc = new NotificationService();
        for (int i = 0; i < 15; i++)
        {
            svc.SendNotification("Student", i.ToString(), EntityOperation.CREATE, "Admin");
        }

        // Act
        var result = _controller.GetNotifications();

        // Assert
        var value = result.Value;
        var countProp = value.GetType().GetProperty("count");
        Assert.AreEqual(10, countProp.GetValue(value));

        svc.Dispose();
    }

    [TestMethod]
    public void MarkAsRead_ReturnsSuccessJson()
    {
        var result = _controller.MarkAsRead(1);

        Assert.IsNotNull(result);
        var value = result.Value;
        var successProp = value.GetType().GetProperty("success");
        Assert.AreEqual(true, successProp.GetValue(value));
    }
}

