using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Http;
using System;

namespace ContosoUniversity.Tests.Controllers;

// Concrete test subclass to test BaseController's protected members
internal sealed class TestableBaseController : BaseController
{
    public TestableBaseController(SchoolContext context) : base(context) { }

    public void InvokeSendEntityNotification(string entityType, string entityId, EntityOperation operation)
    {
        SendEntityNotification(entityType, entityId, operation);
    }

    public void InvokeSendEntityNotification(string entityType, string entityId, string entityDisplayName, EntityOperation operation)
    {
        SendEntityNotification(entityType, entityId, entityDisplayName, operation);
    }

    public SchoolContext GetDb() => db;
    public NotificationService GetNotificationService() => notificationService;
}

[TestClass]
public sealed class BaseControllerTests
{
    private SchoolContext _context;
    private TestableBaseController _controller;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _controller = new TestableBaseController(_context);
        _controller.ControllerContext = new ControllerContext
        {
            HttpContext = new DefaultHttpContext()
        };

        // Drain queue to prevent inter-test interference
        var svc = new NotificationService();
        while (svc.ReceiveNotification() != null) { }
        svc.Dispose();
    }

    [TestCleanup]
    public void Cleanup()
    {
        var svc = new NotificationService();
        while (svc.ReceiveNotification() != null) { }
        svc.Dispose();

        _controller.Dispose();
        _context.Dispose();
    }

    [TestMethod]
    public void Constructor_SetsDbContext()
    {
        Assert.IsNotNull(_controller.GetDb());
        Assert.AreSame(_context, _controller.GetDb());
    }

    [TestMethod]
    public void Constructor_InitializesNotificationService()
    {
        Assert.IsNotNull(_controller.GetNotificationService());
    }

    [TestMethod]
    public void SendEntityNotification_WithoutDisplayName_DoesNotThrow()
    {
        _controller.InvokeSendEntityNotification("Student", "1", EntityOperation.CREATE);
        // Should not throw - notification is enqueued silently
    }

    [TestMethod]
    public void SendEntityNotification_WithDisplayName_DoesNotThrow()
    {
        _controller.InvokeSendEntityNotification("Student", "1", "John Smith", EntityOperation.CREATE);
        // Should not throw - notification is enqueued silently
    }

    [TestMethod]
    public void SendEntityNotification_WithoutDisplayName_EnqueuesNotification()
    {
        _controller.InvokeSendEntityNotification("Course", "42", EntityOperation.UPDATE);

        var svc = new NotificationService();
        var notification = svc.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Course", notification.EntityType);
        Assert.AreEqual("42", notification.EntityId);
        Assert.AreEqual("UPDATE", notification.Operation);
        Assert.AreEqual("System", notification.CreatedBy);
        svc.Dispose();
    }

    [TestMethod]
    public void SendEntityNotification_WithDisplayName_EnqueuesNotificationWithDisplayName()
    {
        _controller.InvokeSendEntityNotification("Department", "5", "Engineering", EntityOperation.DELETE);

        var svc = new NotificationService();
        var notification = svc.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Department", notification.EntityType);
        Assert.AreEqual("5", notification.EntityId);
        Assert.AreEqual("DELETE", notification.Operation);
        Assert.AreEqual("Department 'Engineering' has been deleted", notification.Message);
        svc.Dispose();
    }

    [TestMethod]
    [DataRow(EntityOperation.CREATE, DisplayName = "CREATE operation")]
    [DataRow(EntityOperation.UPDATE, DisplayName = "UPDATE operation")]
    [DataRow(EntityOperation.DELETE, DisplayName = "DELETE operation")]
    public void SendEntityNotification_AllOperations_DoNotThrow(EntityOperation operation)
    {
        _controller.InvokeSendEntityNotification("Entity", "1", "Test", operation);
        // Verify no exception is thrown for any operation type
    }

    [TestMethod]
    public void Dispose_DisposesDbAndNotificationService()
    {
        var context = TestHelpers.CreateInMemoryContext();
        var controller = new TestableBaseController(context);

        // This should not throw
        controller.Dispose();

        // Verify the context is disposed by checking for ObjectDisposedException
        Assert.ThrowsException<ObjectDisposedException>(() => context.Students.ToList());
    }
}

