using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Data;
using Microsoft.Extensions.Configuration;
using System.Collections.Generic;

namespace ContosoUniversity.Tests.Data;

[TestClass]
public sealed class SchoolContextFactoryTests
{
    [TestMethod]
    public void Create_WithValidConnectionString_ReturnsSchoolContext()
    {
        // Arrange
        var inMemorySettings = new Dictionary<string, string>
        {
            { "ConnectionStrings:DefaultConnection", "Server=(localdb)\\mssqllocaldb;Database=TestDb;Trusted_Connection=True;" }
        };
        var configuration = new ConfigurationBuilder()
            .AddInMemoryCollection(inMemorySettings)
            .Build();

        // Act
        var context = SchoolContextFactory.Create(configuration);

        // Assert
        Assert.IsNotNull(context);
        Assert.IsInstanceOfType<SchoolContext>(context);

        context.Dispose();
    }

    [TestMethod]
    public void Create_ReturnsNewInstanceEachCall()
    {
        // Arrange
        var inMemorySettings = new Dictionary<string, string>
        {
            { "ConnectionStrings:DefaultConnection", "Server=(localdb)\\mssqllocaldb;Database=TestDb;Trusted_Connection=True;" }
        };
        var configuration = new ConfigurationBuilder()
            .AddInMemoryCollection(inMemorySettings)
            .Build();

        // Act
        var context1 = SchoolContextFactory.Create(configuration);
        var context2 = SchoolContextFactory.Create(configuration);

        // Assert
        Assert.IsNotNull(context1);
        Assert.IsNotNull(context2);
        Assert.AreNotSame(context1, context2);

        context1.Dispose();
        context2.Dispose();
    }

    [TestMethod]
    public void Create_WithNullConnectionString_ThrowsException()
    {
        // Arrange - config with no connection string
        var inMemorySettings = new Dictionary<string, string>();
        var configuration = new ConfigurationBuilder()
            .AddInMemoryCollection(inMemorySettings)
            .Build();

        // Act & Assert - SqlServer provider throws when connection string is null
        Assert.ThrowsException<InvalidOperationException>(() =>
        {
            SchoolContextFactory.Create(configuration);
        });
    }
}

